import Vue from "vue";
import Vuex from "vuex";
import VuexORM from "@vuex-orm/core";
import { ArtistModel, EntityModel, ConservationWorkModel } from "@/models";

Vue.use(Vuex);

const database = new VuexORM.Database();

database.register(ArtistModel);
database.register(EntityModel);
database.register(ConservationWorkModel);

const store = new Vuex.Store({
  plugins: [VuexORM.install(database)]
});

export default store;
