<template>
  <section class="section">
    <b-steps v-model="activeStep">
      <b-step-item label="Informazioni generali" :clickable="true">
        <div class="box">
          <ArtworkGeneralInfo v-model="info" />
        </div>
      </b-step-item>

      <b-step-item label="Immagini" :clickable="true">
        <div class="box">
          <ImageGalleryField v-model="images" />
        </div>
      </b-step-item>

      <b-step-item label="Conferma" :clickable="true">
        <div class="box">
          <div class="content">
            <p>
              Cliccando su
              <strong>Conferma</strong> verrà visualizzato il condition report generato
            </p>
          </div>

          <b-field>
            <b-button type="is-success" class="is-fullwidth" @click="showConditionReport">Conferma</b-button>
          </b-field>
        </div>
      </b-step-item>
    </b-steps>
  </section>
</template>

<script>
import ArtworkGeneralInfo from "@/components/ArtworkGeneralInfo";
import ImageGalleryField from "@/components/ImageGalleryField";

export default {
  name: "CreateArtwork",
  components: { ArtworkGeneralInfo, ImageGalleryField },

  data() {
    return {
      info: undefined,
      images: undefined,
      activeStep: 0
    };
  },

  computed: {
    artwork: function() {
      return {
        ...this.info,
        images: this.images
      };
    }
  },

  methods: {
    showConditionReport: function() {
      this.$router.push({
        name: "condition-report",
        params: {
          artwork: this.artwork
        }
      });
    }
  }
};
</script>

