export class AnnotableCanvas {
  constructor(canvas, image, radiusRatio = 0.02, strokeRadiusReduction = 0.1) {
    this.canvas = canvas;
    this.image = image;
    this.height = image.height;
    this.width = image.width;

    // init the canvas
    this.canvas.width = this.width;
    this.canvas.height = this.height;
    this.ctx = this.canvas.getContext("2d");

    this.clearCanvas();

    // set radius
    if (this.width > this.height) this.radius = this.width * radiusRatio;
    else this.radius = this.height * radiusRatio;

    // set stroke width
    this.ctx.lineWidth = this.radius * strokeRadiusReduction;

    // set text font
    this.ctx.font = `${this.radius}px sans-serif`;
  }

  clearCanvas() {
    // clean canvas
    this.ctx.fillStyle = "white";
    this.ctx.fillRect(0, 0, this.width, this.height);
    this.ctx.drawImage(this.image, 0, 0, this.width, this.height);
  }

  getImage() {
    return this.canvas.toDataURL("image/png");
  }

  drawAnnotations(annotations) {
    this.clearCanvas();

    for (let i = 0; i < annotations.length; i++) {
      const x = annotations[i].x;
      const y = annotations[i].y;
      const number = annotations[i]._number;

      // draw circle
      this.ctx.fillStyle = "rgba(237, 255, 45, 0.5)";
      this.ctx.strokeStyle = "black";
      this.ctx.beginPath();
      this.ctx.arc(x, y, this.radius, 0, 2 * Math.PI);
      this.ctx.fill();
      this.ctx.stroke();

      // write text inside
      this.ctx.fillStyle = "rgba(255, 255, 255)";
      this.ctx.fillText(
        number,
        x - this.radius / 2 + this.ctx.lineWidth,
        y + this.radius / 2 - this.ctx.lineWidth
      );
    }
  }
}