import Vue from "vue";
import VueRouter from "vue-router";
import CreateArtwork from "@/views/CreateArtwork";
import ConditionReport from "@/views/ConditionReport";

Vue.use(VueRouter);

const routes = [
  {
    path: "/",
    name: "create-artwork",
    component: CreateArtwork
  },

  {
    path: "/output",
    name: "condition-report",
    component: ConditionReport,
    props: true
  }
];

const router = new VueRouter({
  routes
});

export default router;
