<template>
  <b-field grouped>
    <b-field label="Larghezza" expanded>
      <b-input v-model="width" :icon="icon"></b-input>
    </b-field>

    <b-field label="Altezza" expanded>
      <b-input v-model="height" :icon="icon"></b-input>
    </b-field>

    <b-field label="Profondità" expanded>
      <b-input v-model="depth" :icon="icon"></b-input>
    </b-field>
  </b-field>
</template>

<script>
export default {
  name: "MeasureField",
  props: ["value", "icon"],

  data() {
    return {
      height: "",
      width: "",
      depth: ""
    };
  },

  computed: {
    measure: function() {
      let measure = "";

      if (this.width !== "") measure += `${this.width} W`;
      if (this.height !== "") measure += ` x ${this.height} H`;
      if (this.depth !== "") measure += ` x ${this.depth} D`;

      return measure;
    }
  },

  watch: {
    measure: function(newVal) {
      this.$emit("input", newVal);
    }
  }
};
</script>

