<template>
  <section>
    <UploadImageField @input="(i) => image = i" v-if="image === null" ref="upload" />
    <AnnotableImageField v-model="imageObj" @submit="$emit('input', imageObj)" v-else />
  </section>
</template>

<script>
import AnnotableImageField from "@/components/AnnotableImageField";

export default {
  name: "ImageFormField",
  components: { AnnotableImageField },
  props: {
    value: {
      type: Object,
      default: function() {
        return {
          image: null,
          annotations: [],
          caption: null
        };
      }
    }
  },

  mounted: function() {
    const vm = this;

    if (this.image === null)
      this.$nextTick(function() {
        vm.$refs.upload.$el.click()
      });
  },

  data: function() {
    return {
      image: this.value.image,
      annotations: this.value.annotations,
      caption: this.value.caption
    };
  },

  computed: {
    imageObj: {
      get: function() {
        return {
          image: this.image,
          annotations: this.annotations,
          caption: this.caption
        };
      },

      set: function(newVal) {
        this.image = newVal.image;
        this.annotations = newVal.annotations;
        this.caption = newVal.caption;
      }
    }
  }
};
</script>

<style scoped>
.workings-table {
  height: 100vh;
  width: 100%;
}

.image {
  height: 100vh;
  display: flex;
  justify-content: center;
  background-color: grey;
  position: relative;
  overflow-x: scroll;
}

.image canvas {
  background-color: white;
}
</style>
