<template>
  <b-autocomplete
    v-model="searched"
    :data="filteredCollection"
    field="readable"
    @select="x => $emit('input', x)"
    :icon="icon"
  />
</template>

<script>
export default {
  name: "AutocompleteField",
  props: ["value", "model", "icon"],

  data() {
    return {
      searched: this.value || ""
    };
  },

  watch: {
    searched: function(newVal) {
      this.$emit("input", newVal);
    }
  },

  computed: {
    collection: function() {
      return this.model.all();
    },

    filteredCollection() {
      return this.collection.filter(
        x => x.readable.toLowerCase().indexOf(this.searched.toLowerCase()) >= 0
      );
    }
  }
};
</script>

