<template>
  <div class="container">
    <div class="columns">
      <div class="column is-12">
        <div class="columns gallery">
          <div class="column is-1 item box add-box">
            <b-upload @input="loadImage" @click="showAddImageForm = true" class="button-container">
              <a class="button is-primary" id="addButton">
                <b-icon icon="plus" />
              </a>
            </b-upload>
          </div>

          <div class="column is-2 box item" v-for="(image, i) in images" :key="i">
            <figure class="image">
              <img :src="image.image" alt="Placeholder image" />
            </figure>

            <hr />

            <p v-if="image.caption && image.caption !== ''">{{ image.caption }}</p>
            <p>Annotazioni: {{ image.annotations.length }}</p>

            <div class="small-buttons">
              <b-field>
                <b-button type="is-primary" rounded @click="launchEditImage(image, i)">
                  <b-icon icon="pencil" />
                </b-button>
              </b-field>
              <b-field>
                <b-button type="is-danger" @click="removeImage(image, i)" rounded>
                  <b-icon icon="delete" />
                </b-button>
              </b-field>
            </div>
          </div>
        </div>
      </div>
    </div>

    <b-modal :active.sync="showImageForm" full-screen :can-cancel="false">
      <ImageFormField @input="addImage" v-model="imageForForm" />
    </b-modal>
  </div>
</template>

<script>
import ImageFormField from "@/components/ImageFormField";

export default {
  name: "ImageGalleryField",
  components: { ImageFormField },
  props: {
    value: {
      type: Array,
      default: () => []
    }
  },

  data() {
    return {
      showImageForm: false,
      imageForForm: null,

      images: this.value
    };
  },

  methods: {
    loadImage: function(file) {
      const vm = this;
      let fr = new FileReader();
      fr.addEventListener("loadend", function(e) {
        vm.imageForForm = {
          image: e.target.result,
          annotations: [],
          caption: null
        };

        vm.showImageForm = true;
      });

      fr.readAsDataURL(file);
    },

    addImage: function(img) {
      this.showImageForm = false;
      this.images.push(img);
      this.$emit("input", this.images);
    },

    removeImage: function(toBeRemoved, i) {
      this.images.splice(i, 1);
    },

    launchEditImage: function(toBeRemoved, i) {
      this.showImageForm = true;
      this.imageToEdit = toBeRemoved;
      this.removeImage(toBeRemoved, i);
    },

    submit: function() {
      this.$emit("input", this.images);
    }
  },

  watch: {
    images: function() {
      this.submit();
    }
  }
};
</script>

