<template>
  <div class="container">
    <div class="columns">
      <div class="column is-full">
        <div class="columns gallery">
          <div class="column is-one-third box item" v-for="(image, i) in images" :key="i">
            <figure class="image">
              <img :src="image.image" alt="Placeholder image" />
            </figure>

            <hr />

            <p v-if="image.caption && image.caption !== ''">{{ image.caption }}</p>
            <p>Annotazioni: {{ image.annotations.length }}</p>

            <div class="small-buttons">
              <b-field>
                <b-button type="is-primary" rounded @click="launchShowImageModal(image)">
                  <b-icon icon="eye" />
                </b-button>
              </b-field>
            </div>
          </div>
        </div>
      </div>
    </div>

    <b-modal :active.sync="showImageModal">
      <AnnotatedImage :image="imageToShow" />
    </b-modal>
  </div>
</template>

<script>
import AnnotatedImage from "@/components/AnnotatedImage";

export default {
  name: "ImageGallery",
  components: { AnnotatedImage },
  props: {
    images: {
      type: Array,
      default: () => []
    }
  },

  data() {
    return {
      showImageModal: false,
      imageToShow: null
    };
  },

  methods: {
    launchShowImageModal: function(image) {
      this.imageToShow = image;
      this.showImageModal = true;
    }
  }
};
</script>

