<template>
  <div class="container">
    <!-- General informations -->
    <b-field label="Proprietario">
      <AutocompleteField v-model="owner" :model="ownerModel" icon="account" />
    </b-field>
    <b-field label="Valore assicurativo">
      <b-input v-model="assicurative_value" type="number" icon="currency-eur" />
    </b-field>
    <hr />

    <b-field label="Titolo">
      <b-input v-model="title" icon="format-title" />
    </b-field>
    <b-field label="Autore">
      <AutocompleteField v-model="author" :model="authorModel" icon="pencil" />
    </b-field>
    <b-field label="Data">
      <b-datepicker icon="calendar-today" v-model="date" />
    </b-field>
    <b-field label="Misure (cm)">
      <MeasureField icon="ruler" v-model="measure" />
    </b-field>
    <hr />

    <b-field label="Materiale e tecnica">
      <b-input v-model="material_technique" icon="pencil" />
    </b-field>
    <b-field label="Tipologia">
      <b-input v-model="typology" icon="image" />
    </b-field>
    <b-field label="Misure cornice/cassa (cm)">
      <MeasureField icon="ruler" v-model="cover_measure" />
    </b-field>
    <b-field label="Protezione">
      <b-input v-model="protection" icon="shield" />
    </b-field>
  </div>
</template>

<script>
import { EntityModel, ArtistModel } from "@/models";
import AutocompleteField from "@/components/AutocompleteField";
import MeasureField from "@/components/MeasureField";

export default {
  name: "ArtworkGeneralInfo",
  components: { AutocompleteField, MeasureField },
  props: {
    value: {
      type: Object,
      default: function() {
        return {
          owner: null,
          assicurative_value: null,

          title: null,
          author: null,
          date: null,
          measure: null,

          typology: null,
          material_technique: null,
          cover_measure: null,
          protection: null
        };
      }
    }
  },

  data() {
    return {
      owner: this.value.owner,
      ownerModel: EntityModel,
      assicurative_value: this.value.assicurative_value,

      title: this.value.title,
      author: this.value.author,
      authorModel: ArtistModel,
      date: this.value.date,
      measure: this.value.measure,

      typology: this.value.typology,
      material_technique: this.value.material_technique,
      cover_measure: this.value.cover_measure,
      protection: this.value.protection
    };
  },

  computed: {
    informations: function() {
      return {
        owner: this.owner,
        assicurative_value: this.assicurative_value,
        title: this.title,
        author: this.author,
        date: this.date,
        measure: this.measure,
        typology: this.typology,
        material_technique: this.material_technique,
        cover_measure: this.cover_measure,
        protection: this.protection
      };
    }
  },

  watch: {
    informations: function() {
      this.$emit("input", this.informations);
    }
  }
};
</script>

