<template>
  <canvas ref="canvas" @click="this.clicked"></canvas>
</template>

<script>
import { AnnotableCanvas } from "@/AnnotableCanvas";

export default {
  name: "AnnotableCanvas",
  props: {
    image : {
      type: String
    },
    annotations: {
      type: Array
    },
    edit: {
      type: Boolean,
      default: true
    }
  },

  data() {
    return {
      annotable: null
    };
  },

  created() {
    this.loadImage(this.image, this.annotations);

    if (this.edit)
      this.$buefy.toast.open(
        "Clicca sul punto in cui vuoi aggiungere un'annotazione"
      );
  },

  methods: {
    loadImage: function(img, annotations = []) {
      this.image = img;

      // set canvas width and height based in image width and height
      let imageObj = new Image();
      const vm = this;
      imageObj.addEventListener("load", function(i) {
        const loadedImage = i.target;
        vm.annotable = new AnnotableCanvas(vm.$refs.canvas, loadedImage);
        vm.annotable.drawAnnotations(annotations);
      });
      imageObj.src = img;
    },

    clicked: function(e) {
      // https://stackoverflow.com/questions/3234256/find-mouse-position-relative-to-element
      // https://stackoverflow.com/questions/43853119/javascript-wrong-mouse-position-when-drawing-on-canvas
      let rect = e.target.getBoundingClientRect();
      let x = ((e.clientX - rect.left) / rect.width) * e.target.width;
      let y = ((e.clientY - rect.top) / rect.height) * e.target.height;
      this.$emit("click", { x: x, y: y });
    }
  },

  watch: {
    image: function(newImage) {
      this.loadImage(newImage, this.annotations);
    },

    annotations: function(newAnnotations) {
      this.annotable.drawAnnotations(newAnnotations);
    }
  }
};
</script>

