<template>
  <section>
    <div class="workings-table">
      <div class="image">
        <AnnotableCanvas
          @click="addAnnotation"
          :image="image"
          :annotations="annotations"
        />
      </div>

      <section class="section">
        <div class="columns">
          <div class="column is-half">
            <b-field label="Annotazioni">
              <b-field grouped group-multiline>
                <div class="control" v-for="(annotation, i) in annotations" :key="i">
                  <b-taglist attached>
                    <b-tag type="is-warning">{{ annotation._number }}</b-tag>
                    <b-tag
                      type="is-info"
                      closable
                      @close="removeAnnotation(i)"
                    >{{ annotation.text }}</b-tag>
                  </b-taglist>
                </div>
              </b-field>
            </b-field>
          </div>

          <div class="column is-half">
            <b-field label="Didascalia">
              <b-input v-model="caption" />
            </b-field>

            <b-field>
              <b-button @click="submitImage" type="is-primary" class="is-fullwidth">Conferma</b-button>
            </b-field>
          </div>
        </div>
      </section>
    </div>
  </section>
</template>

<script>
import AnnotableCanvas from "@/components/AnnotableCanvas";

export default {
  name: "AnnotableImageField",
  components: { AnnotableCanvas },
  props: ["value"],

  data: function() {
    let i = 0;

    let annotations = this.value.annotations;
    for (i = 1; i <= annotations.length; i++) annotations[i - 1]._number = i;

    return {
      image: this.value.image,
      annotations: annotations,
      caption: this.value.caption || "",
      annotationNumber: i
    };
  },

  computed: {
    imageObj: function() {
      return {
        image: this.image,
        annotations: this.annotations,
        caption: this.caption
      };
    }
  },

  methods: {
    addAnnotation: function(pos) {
      const vm = this;
      
      // launch annotation dialog
      this.$buefy.dialog.prompt({
        message: "Inserisci l'annotazione in questo punto",
        onConfirm: val => {
          vm.annotations.push({
            _number: vm.annotationNumber++,
            x: pos.x,
            y: pos.y,
            text: val
          });
        }
      });
    },

    removeAnnotation(index) {
      this.annotations.splice(index, 1);
    },

    submitImage() {
      this.$emit("submit", this.imageObj);
    }
  },

  watch: {
    image: function() {
      this.$emit("input", this.imageObj);
    },
    caption: function() {
      this.$emit("input", this.imageObj);
    },
    annotations: function() {
      this.$emit("input", this.imageObj);
    }
  }
};
</script>

<style scoped>
.workings-table {
  height: 100vh;
  width: 100%;
}

.image {
  height: 100vh;
  display: flex;
  justify-content: center;
  background-color: grey;
  position: relative;
  overflow-x: scroll;
}

.image canvas {
  background-color: white;
}
</style>
